6{"ArtifactMetadata":{"RequestFeedback":false,"Summary":"Temporary test script to verify the new modal checkout flow using Puppeteer.","UserFacing":false},"CodeContent":"const puppeteer = require('puppeteer');

(async () => {
  console.log('Launching browser...');
  const browser = await puppeteer.launch({
    headless: true, // running headless is fine
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });
  const page = await browser.newPage();
  await page.setViewport({ width: 1400, height: 900 });

  // Stub session and database variables
  await page.evaluateOnNewDocument(() => {
    sessionStorage.setItem('logged_in_user', 'testcashier');
    sessionStorage.setItem('logged_in_role', 'admin');
    sessionStorage.setItem('tenant_id', 'test-tenant');
    sessionStorage.setItem('tenant_slug', 'test');
    sessionStorage.setItem('tenant_name', 'Doppio Cafe');
    sessionStorage.setItem('allowed_tabs', JSON.stringify(['pos-tab']));
  });

  console.log('Navigating to dashboard...');
  await page.goto('http://localhost:8001/dashboard.html', { waitUntil: 'networkidle2', timeout: 30000 });
  await new Promise(r => setTimeout(r, 2000));

  // Add an item to cart by clicking the first card
  console.log('Adding item to cart...');
  const itemCard = await page.$('.pos-item-card');
  if (itemCard) {
    await itemCard.click();
    await new Promise(r => setTimeout(r, 1000));
  } else {
    console.log('No item cards found on page. Manually adding item to cart via JS...');
    await page.evaluate(() => {
      if (window.RS && window.RS.addToCart) {
        window.RS.addToCart(1); // Add item ID 1
      }
    });
    await new Promise(r => setTimeout(r, 1000));
  }

  // Verify modal is currently hidden
  const modalVisibleInit = await page.evaluate(() => {
    const modal = document.getElementById('checkout-modal');
    return modal ? modal.classList.contains('show') : false;
  });
  console.log('Modal visible initially:', modalVisibleInit);

  // Click Print & Pay trigger button in sidebar
  console.log('Clicking Print & Pay trigger in sidebar...');
  await page.click('#btn-trigger-checkout');
  await new Promise(r => setTimeout(r, 500));

  // Verify modal is now visible
  const modalVisibleAfterClick = await page.evaluate(() => {
    const modal = document.getElementById('checkout-modal');
    return modal ? modal.classList.contains('show') : false;
  });
  console.log('Modal visible after clicking trigger:', modalVisibleAfterClick);

  if (!modalVisibleAfterClick) {
    console.error('Modal failed to open!');
    await browser.close();
    process.exit(1);
  }

  // Verify amount to pay matches grand total
  const modalTotal = await page.evaluate(() => document.getElementById('modal-total-value')?.textContent);
  const cartTotal = await page.evaluate(() => document.getElementById('t-grand')?.textContent);
  console.log(`Cart Grand Total: ${cartTotal}, Modal Displayed Total: ${modalTotal}`);

  // Test toggling payment methods in modal
  console.log('Testing UPI payment method...');
  await page.evaluate(() => {
    const upiBtn = document.querySelector('[data-pay-method="UPI"]');
    if (upiBtn) upiBtn.click();
  });
  await new Promise(r => setTimeout(r, 500));

  const upiVisible = await page.evaluate(() => {
    return document.getElementById('upi-instruction')?.style.display === 'flex';
  });
  console.log('UPI payment instruction panel visible:', upiVisible);

  console.log('Testing Split payment method...');
  await page.evaluate(() => {
    const splitBtn = document.querySelector('[data-pay-method="Split"]');
    if (splitBtn) splitBtn.click();
  });
  await new Promise(r => setTimeout(r, 500));

  const splitVisible = await page.evaluate(() => {
    return document.getElementById('split-calc-inline')?.style.display === 'flex';
  });
  console.log('Split breakdown panel visible:', splitVisible);

  console.log('Testing Cash payment method...');
  await page.evaluate(() => {
    const cashBtn = document.querySelector('[data-pay-method="Cash"]');
    if (cashBtn) cashBtn.click();
  });
  await new Promise(r => setTimeout(r, 500));

  const cashVisible = await page.evaluate(() => {
    return document.getElementById('cash-calc-inline')?.style.display === 'flex';
  });
  console.log('Cash calculator panel visible:', cashVisible);

  // Test quick denominations (Exact)
  console.log('Testing Exact button...');
  await page.evaluate(() => {
    const exactBtn = document.querySelector('.inline-den-btn[data-val="exact"]');
    if (exactBtn) exactBtn.click();
  });
  await new Promise(r => setTimeout(r, 500));

  const receivedVal = await page.evaluate(() => document.getElementById('inline-cash-received')?.value);
  console.log('Received cash amount after Exact click:', receivedVal);

  // Click Cancel to verify close works
  console.log('Clicking Cancel button...');
  await page.click('#btn-cancel-checkout');
  await new Promise(r => setTimeout(r, 500));

  const modalVisibleAfterCancel = await page.evaluate(() => {
    const modal = document.getElementById('checkout-modal');
    return modal ? modal.classList.contains('show') : false;
  });
  console.log('Modal visible after clicking Cancel:', modalVisibleAfterCancel);

  // Re-open and finalize order
  console.log('Re-opening modal to finalize order...');
  await page.click('#btn-trigger-checkout');
  await new Promise(r => setTimeout(r, 500));

  // Set cash received to cover the total
  await page.evaluate(() => {
    const receivedInput = document.getElementById('inline-cash-received');
    const grand = parseFloat(document.getElementById('t-grand').textContent.replace(/[^\d.]/g, '')) || 0;
    if (receivedInput) receivedInput.value = grand;
  });

  console.log('Clicking Print & Pay inside modal...');
  await page.click('#btn-checkout');
  await new Promise(r => setTimeout(r, 1000));

  // Verify modal is closed
  const modalVisibleAfterCheckout = await page.evaluate(() => {
    const modal = document.getElementById('checkout-modal');
    return modal ? modal.classList.contains('show') : false;
  });
  console.log('Modal visible after successful checkout:', modalVisibleAfterCheckout);

  // Verify cart is empty
  const cartItemCount = await page.evaluate(() => document.getElementById('cart-count')?.textContent);
  console.log('Cart item count after checkout:', cartItemCount);

  await browser.close();
  console.log('Test completed successfully!');
})();
